--
-- Table structure for table `contract_version`
--

DROP TABLE IF EXISTS `contract_version`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `contract_version` (
  `version_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '版本ID',
  `contract_id` bigint unsigned NOT NULL COMMENT '所属合同ID',
  `version_no` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '版本号，如v1.0',
  `content_hash` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin NOT NULL COMMENT '合同正文内容哈希，用于变更检测',
  `is_locked` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '是否归档锁定：0未锁定，1已锁定',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_bin COMMENT '合同版本正文内容',
  `file_id` bigint unsigned NOT NULL COMMENT '该版本关联文件ID',
  `created_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT 'SYSTEM_INIT' COMMENT '创建人',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_bin DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `is_deleted` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '逻辑删除：0未删除，1已删除',
  `version` int unsigned NOT NULL DEFAULT '1' COMMENT '乐观锁版本号',
  PRIMARY KEY (`version_id`),
  KEY `idx_contract_id` (`contract_id`),
  KEY `idx_file_id` (`file_id`),
  CONSTRAINT `fk_version_contract` FOREIGN KEY (`contract_id`) REFERENCES `contract_main` (`contract_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_version_file` FOREIGN KEY (`file_id`) REFERENCES `file_info` (`file_id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=18 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_bin COMMENT='合同版本表';
/*!40101 SET character_set_client = @saved_cs_client */;

